#include <bits/stdc++.h>
using namespace std;
const int N=100005;
struct node 
{
    int l,r,id,num;
} q[N];
long long n,m,id[N],ans,a[N],vis[N],block,ans2[N],k;
bool cmp(node x,node y)
{
    if(x.id==y.id) return x.r<y.r;
    return x.id<y.id;
}
void del(int num)
{
    ans-=(vis[a[num]]*vis[a[num]]);
    vis[a[num]]--;
    ans+=(vis[a[num]]*vis[a[num]]);
}
void add(int num)
{
    ans-=(vis[a[num]]*vis[a[num]]);
    vis[a[num]]++;
    ans+=(vis[a[num]]*vis[a[num]]);
}
int main()
{
    cin>>n>>m>>k;
    block=sqrt(n);
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    for(int i=1;i<=m;i++)
    {
        cin>>q[i].l>>q[i].r;
        q[i].id=(q[i].l-1)/block;
        q[i].num=i;
    }
    sort(q+1,q+1+m,cmp);
    int L=1,R=1;
    add(1);
    for(int i=1;i<=m;i++)
    {
        int tl=q[i].l,tr=q[i].r;
        while(L<tl) del(L),L++;
		while(R>tr) del(R),R--;
		while(L>tl) L--,add(L);
		while(R<tr) R++,add(R);
        ans2[q[i].num]=ans;
    }
    for(int i=1;i<=m;i++)
    {
        cout<<ans2[i]<<'\n';
    }
    return 0;
}
